// entityFilterLabel turns the ?filter= scope into a chip label.
func entityFilterLabel(f string) string {
	switch f {
	case "no-sprite":
		return "no sprite assigned"
	default:
		return f
	}
}

// entityKindLabel picks the most-recognizable tag from an entity's tag
// list to show as its "kind". Falls back to a generic label when none
// of the well-known kinds is set.
func entityKindLabel(et entities.EntityType) string {
	known := []string{"tile", "npc", "item", "trigger"}
	for _, k := range known {
		for _, t := range et.Tags {
			if t == k {
				return k
			}
		}
	}
	return "entity"
}

